#!/usr/bin/env bash
# Generated by: npm run collect:benchmark -- --dry-run
# Run from repo root or adjust cd path. Tinyfish agent is ON (do not pass --no-agent).
set -euo pipefail
cd "$(dirname "$0")/../../backend/BigSet_Data_Collection_Agent"

# latest-ai-blog-posts (good)
npm run collect -- run \
  -p 'Can you make me a table of the latest blog posts from OpenAI, Anthropic, and Google DeepMind? I need title, publish date, and URL.' \
  -t 8 \
  -o 'runs/benchmark-cli/01-latest-ai-blog-posts' \
  --required-columns entity_name,latest_post_title,latest_post_date,source_url \
  --expected-stress 'Clear entities and fields; tests current web facts with low ambiguity.'

# saas-pricing-pages (good)
npm run collect -- run \
  -p 'For Stripe, Paddle, and Chargebee, collect the official pricing page URL and the plan names or starting prices shown on the page.' \
  -t 8 \
  -o 'runs/benchmark-cli/02-saas-pricing-pages' \
  --required-columns entity_name,pricing_page_url,plan_or_price,source_url \
  --expected-stress 'Official pricing evidence; should not require a browser agent unless pricing is hidden.'

# earnings-release-pages (good)
npm run collect -- run \
  -p 'Find the latest investor relations earnings release page for Apple, Microsoft, and Nvidia. Include release date, fiscal quarter, and source URL.' \
  -t 8 \
  -o 'runs/benchmark-cli/03-earnings-release-pages' \
  --required-columns entity_name,release_date,fiscal_quarter,source_url \
  --expected-stress 'Latest dated source pages; date precision matters.'

# mcp-docs-pages (good)
npm run collect -- run \
  -p 'I need official docs pages for setting up MCP servers from Anthropic, OpenAI, and Cloudflare. Give me title, URL, and what each page covers.' \
  -t 8 \
  -o 'runs/benchmark-cli/04-mcp-docs-pages' \
  --required-columns entity_name,docs_title,docs_url,summary \
  --expected-stress 'Official docs discovery; should avoid random blog posts.'

# menlo-park-coca-cola (average)
npm run collect -- run \
  -p 'restaurants in Menlo Park that serve Coca-Cola' \
  -t 8 \
  -o 'runs/benchmark-cli/05-menlo-park-coca-cola' \
  --required-columns entity_name,address,serves_requested_item,source_url \
  --expected-stress 'Short but understandable; menu evidence may require deeper page checks.'

# hcmc-bakery-products (average)
npm run collect -- run \
  -p 'bakeries in Ho Chi Minh City with pastry product pages, product name, product URL, and bakery name' \
  -t 8 \
  -o 'runs/benchmark-cli/06-hcmc-bakery-products' \
  --required-columns bakery_name,product_name,product_url,source_url \
  --expected-stress 'Product-page proof and local business search.'

# ny-ai-startup-careers (average)
npm run collect -- run \
  -p 'AI startups in New York that have careers pages. I want company name, website, and whether they look like they are hiring.' \
  -t 8 \
  -o 'runs/benchmark-cli/07-ny-ai-startup-careers' \
  --required-columns entity_name,company_website,careers_page_url,is_hiring \
  --expected-stress 'Careers-page verification with partial data accepted.'

# vietnam-fintech-sites (average)
npm run collect -- run \
  -p 'Vietnamese fintech startups with official websites, short description, and source URL' \
  -t 8 \
  -o 'runs/benchmark-cli/08-vietnam-fintech-sites' \
  --required-columns entity_name,official_website,description,source_url \
  --expected-stress 'Company discovery with official-source preference.'

# district-one-coffee-sites (average)
npm run collect -- run \
  -p 'coffee shops in District 1 Ho Chi Minh City that have their own website or online menu' \
  -t 8 \
  -o 'runs/benchmark-cli/09-district-one-coffee-sites' \
  --required-columns entity_name,website_or_menu_url,address,source_url \
  --expected-stress 'Local search plus website/menu disambiguation.'

# amazon-starbucks-products (average)
npm run collect -- run \
  -p 'I saw there is a Starbucks shop on Amazon. Can you scrape the Starbucks products with name, price, image, and whether each item is in stock?' \
  -t 8 \
  -o 'runs/benchmark-cli/10-amazon-starbucks-products' \
  --required-columns product_name,price,image_url,in_stock \
  --expected-stress 'Ecommerce listing freshness; likely needs browser-style verification.'

# california-insurance-prices (bad)
npm run collect -- run \
