  -o 'runs/benchmark-cli/11-california-insurance-prices' \
  --required-columns provider_name,quote_page_url,missing_inputs,source_url \
  --expected-stress 'Missing driver, vehicle, ZIP, coverage, deductible; should ask clarifying questions.'

